import { IntegrationServices } from '@domain/integrations';
import { allIntegrations } from '@pages/Settings/pages/integrations/IntegrationDirectory/CreateList/integrationCreateUtils';
import { useRollbar } from '@rollbar/react';
import { ErrorScene } from '@ui/components/ErrorScene';
import { useTranslation } from 'react-i18next';
import { useParams, useSearchParams } from 'react-router-dom';
import { REASON_INVALID_PROVIDER, REASON_REQUIRED_PARAMS } from './error-constants';
import { handleOauthCallbackError } from './handleOauthCallbackError';
import { OauthCallbackRedirect } from './OauthCallbackRedirect';
import { checkRequiredParams } from './utils';

const OauthRedirectPage = () => {
  const [searchParams] = useSearchParams();
  const { service } = useParams<{ service: IntegrationServices }>();
  const rollbar = useRollbar();
  const { t } = useTranslation('integrationDirectory', {
    keyPrefix: 'oauth.errors',
  });

  if (!service || (!allIntegrations[service] && service !== 'blackbaud')) {
    handleOauthCallbackError({
      reason: REASON_INVALID_PROVIDER,
      rollbar,
    });

    // if service isn't defined, show error scene,
    // users shouldn't be at this page without a provider
    return <ErrorScene description={t('noProvider')} />;
  }

  // check if we have the params we need for a successful oauth callback
  const { isOk, params = {} } = checkRequiredParams({ searchParams, service });

  if (!isOk) {
    handleOauthCallbackError({
      reason: REASON_REQUIRED_PARAMS,
      rollbar,
      service,
    });

    // if we don't have what we need for callback to succeed, show the error
    return <ErrorScene description={t('missingParams')} />;
  }

  return <OauthCallbackRedirect params={params} service={service} />;
};

export default OauthRedirectPage;

