import { IntegrationServices } from '@domain/integrations';
import { useRollbar } from '@rollbar/react';
import { OauthRequestParams, useOauthCallback } from '@state/oauth/useOauthCallback';
import { ErrorScene } from '@ui/components/ErrorScene';
import { useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { REASON_REQUEST_FAILED } from './error-constants';
import { handleOauthCallbackError } from './handleOauthCallbackError';
import { handleOauthCallbackSuccess } from './handleOauthCallbackSuccess';
import { OauthLoading } from './OauthLoading';

type OauthRedirectProps = {
  params: OauthRequestParams;
  service: IntegrationServices;
};

export const OauthCallbackRedirect = ({ params, service }: OauthRedirectProps) => {
  const { isError, mutate } = useOauthCallback(service);
  const rollbar = useRollbar();
  const { t } = useTranslation('integrationDirectory', {
    keyPrefix: 'oauth.errors',
  });

  useEffect(() => {
    mutate(params, {
      onError: () => {
        handleOauthCallbackError({
          reason: REASON_REQUEST_FAILED,
          rollbar,
          service,
        });
      },
      onSuccess: (data) => {
        handleOauthCallbackSuccess(data);
      },
    });
  }, [mutate, params, rollbar, service]);

  if (isError) {
    return <ErrorScene description={t('requestFailed')} />;
  }

  return <OauthLoading />;
};

