type CognitoConfig = {
  clientId?: string;
  domain?: string;
  redirectUri?: string;
  responseType: string;
  scope: string;
};

const getCognitoConfig = (): CognitoConfig => ({
  clientId: process.env.VITE_COGNITO_CLIENT_ID,
  domain: process.env.VITE_COGNITO_DOMAIN,
  redirectUri: process.env.VITE_COGNITO_REDIRECT_URI,
  responseType: process.env.VITE_COGNITO_RESPONSE_TYPE || 'code',
  scope: process.env.VITE_COGNITO_SCOPE || 'openid profile email',
});

const normalizeDomain = (domain: string) => {
  const trimmed = domain.replace(/\/+$/, '');
  return trimmed.startsWith('http') ? trimmed : `https://${trimmed}`;
};

export const buildCognitoState = (returnTo: string) =>
  new URLSearchParams({ return_to: returnTo }).toString();

export const parseCognitoStateReturnTo = (state: string | null) => {
  if (!state) {
    return null;
  }

  const params = new URLSearchParams(state);
  return params.get('return_to');
};

export const getCognitoRedirectUri = () => getCognitoConfig().redirectUri;

export const getCognitoAuthorizeUrl = ({ returnTo }: { returnTo: string }) => {
  const { clientId, domain, redirectUri, responseType, scope } = getCognitoConfig();

  if (!clientId || !domain || !redirectUri) {
    return null;
  }

  const baseUrl = `${normalizeDomain(domain)}/oauth2/authorize`;
  const params = new URLSearchParams({
    client_id: clientId,
    redirect_uri: redirectUri,
    response_type: responseType,
    scope,
    state: buildCognitoState(returnTo),
  });

  return `${baseUrl}?${params.toString()}`;
};

export const getSafeReturnTo = (returnTo: string | null, fallback = '/accounts') => {
  if (!returnTo) {
    return fallback;
  }

  try {
    const parsed = new URL(returnTo, window.location.origin);
    if (parsed.origin !== window.location.origin) {
      return fallback;
    }

    return parsed.href;
  } catch {
    return fallback;
  }
};
