import { Center } from '@chakra-ui/layout';
import { ApiClient } from '@service/anedot/client';
import {
  getCognitoRedirectUri,
  getSafeReturnTo,
  parseCognitoStateReturnTo,
} from '@utils/auth/cognito';
import { getApiHostname } from '@utils/getApiHostname';
import { ErrorScene } from '@ui/components/ErrorScene';
import { Loading } from '@ui/components/Loading';
import { useEffect, useMemo, useState } from 'react';
import { useSearchParams } from 'react-router-dom';

const CognitoCallback = () => {
  const [searchParams] = useSearchParams();
  const [hasError, setHasError] = useState(false);

  const returnTo = useMemo(() => {
    const state = searchParams.get('state');
    return getSafeReturnTo(parseCognitoStateReturnTo(state));
  }, [searchParams]);

  useEffect(() => {
    const code = searchParams.get('code');
    const state = searchParams.get('state');
    const redirectUri = getCognitoRedirectUri();

    if (!code || !redirectUri) {
      setHasError(true);
      return;
    }

    const client = new ApiClient({ baseURL: getApiHostname(), performRedirect: false });

    client
      .post('auth/cognito/callback', {
        code,
        redirectUri,
        state,
      })
      .then(() => {
        window.location.assign(returnTo);
      })
      .catch(() => {
        setHasError(true);
      });
  }, [returnTo, searchParams]);

  if (hasError) {
    return <ErrorScene description="Unable to complete login. Please try again." />;
  }

  return (
    <Center flex={1} height="100vh">
      <Loading />
    </Center>
  );
};

export default CognitoCallback;
