import { FeatureFlag } from '@state/featureFlags';
import { useFeatureFlags } from '@state/featureFlags/queries/useFeatureFlags';
import { isDevelopment } from '@utils';
import { createContext, useContext } from 'react';

let devOverrides: Record<string, boolean> = {};

if (isDevelopment()) {
  import('../devOverrides.json')
    .then((module) => {
      devOverrides = module.default;
    })
    .catch((error) => {
      console.error('Failed to load config file:', error);
    });
}

const _useFeatureFlag = <T = boolean>(
  name: FeatureFlag,
  defaultValue: boolean | T = false,
  accountId?: string | null
): boolean | T => {
  const { isEnabled, isError, isFetched } = useFeatureFlags({ accountId });
  if (devOverrides[name]) {
    return devOverrides[name] as boolean;
  }
  return !isFetched || isError ? defaultValue : isEnabled(name);
};

export const UseFeatureFlagContext = createContext(_useFeatureFlag);

export const useFeatureFlag = <T = boolean>(
  name: FeatureFlag,
  defaultValue?: boolean | T,
  accountId?: string | null
) => useContext(UseFeatureFlagContext)(name, defaultValue, accountId);

